200: const State = struct {
201:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
202:     // longer than 16.
203:     buffer_effective: [16]Span,
204:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
205:     // value (255), we will reset the effective buffer and this value.
206:     buffer_length: u8 = 0,
207:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
208:     // calculate backspaces and replacement characters.
209:     buffer_modification_index: ?u8 = null,
210:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
211:     // switch, input cancellation, exceed effective buffer). This value is only used in .telex mode
212:     // and the engine is working on position on or after literal index, the engine will skip
213:     // Vietnamese input processing (we only count valid numbers, null mean no literal index).
214:     literal_index: ?u8 = null,
215:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
216:     mode: InputMode = .literal,
217: 
218:     // Initialize the State on allocated memory.
219:     fn init(self: *State) void {
220:         self.* = .{
221:             .buffer_effective = undefined,
222:         };
223:     }
224: 
225:     fn add(self: *State, c: u8) void {
226:         // Only allow a-zA-Z.
227:         assert(std.ascii.isAlphabetic(c));
228: 
229:         // The buffer_modification index must be inbound of the buffer_effective.
230:         assert(self.buffer_modification_index == null or self.buffer_modification_index.? < self.buffer_effective.len);
231: 
232:         // Input mode must be either .literal or .telex.
233:         assert(self.mode == .literal or self.mode == .telex);
234: 
235:         // Should never set literal_index in .literal mode.
236:         if (self.mode == .literal) {
237:             assert(self.literal_index == null);
238:         }
239: 
240:         if (self.literal_index) |literal_index| {
241:             // When literal_index is set, mode must be .telex.
242:             assert(self.mode == .telex);
243:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
244:             // because we won't process Vietnamese input outside the buffer_effective.
245:             assert(literal_index <= self.buffer_effective.len);
246:             // The literal_index value must be less than buffer length.
247:             assert(literal_index < self.buffer_length);
248:         }
249: 
250:         switch (c) {
251:             'A', 'a' => { // circumflex.
252:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
253:                     // 1. Enable literal input when literal_index is set or on literal mode. The
254:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
255:                     // 2. Append literal because no previous span existed. Continue Vietnamese
256:                     // processing on next input.
257:                     self.append_literal(c);
258:                     // Set modification index to null because we didn't modify any existing span.
259:                     self.buffer_modification_index = null;
260:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .empty) {
261:                     // 3. Previous span is 'A' or 'a', apply circumflex.
262:                     self.buffer_effective[self.buffer_length - 1].diacritic = .circumflex;
263:                     // Set modification index for calculating synthetic backspace.
264:                     self.buffer_modification_index = self.buffer_length - 1;
265:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .breve) {
266:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
267:                     self.buffer_effective[self.buffer_length - 1].diacritic = .circumflex;
268:                     // Set modification index for calculating synthetic backspace.
269:                     self.buffer_modification_index = self.buffer_length - 1;
270:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .circumflex) {
271:                     // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
272:                     self.buffer_effective[self.buffer_length - 1].diacritic = .empty;
273:                     // Set modification index for calculating synthetic backspace.
274:                     self.buffer_modification_index = self.buffer_length - 1;
275:                     // Start literal input from this position.
276:                     self.literal_index = self.buffer_length;
277:                     // Append literal 'A' or 'a'.
278:                     self.append_literal(c);
279:                 } else if (std.ascii.toLower(self.buffer_effective[self.buffer_length - 1].base) != std.ascii.toLower(c)) {
280:                     // 6. Append literal when previous span is not 'A', 'a' and its variants.
281:                     if (self.buffer_length == self.buffer_effective.len) {
282:                         // Start literal input from this position when buffer_length exceeds the buffer_effective.
283:                         self.literal_index = self.buffer_length;
284:                     }
285:                     self.append_literal(c);
286:                     // No modification.
287:                     self.buffer_modification_index = null;
288:                 } else {
289:                     unreachable;
290:                 }
291:             },
292:             'C', 'c' => {}, // fill missing diacritic, e.g. cước.
293:             'D', 'd' => {}, // bar.
294:             'E', 'e' => {}, // circumflex.
295:             'F', 'f' => {}, // falling.
296:             'I', 'i' => {}, // fill missing diacritic, e.g. người.
297:             'J', 'j' => {}, // falling_glottalized.
298:             'M', 'm' => {}, // fill missing diacritic, e.g. cườm.
299:             'N', 'n' => {}, // fill missing diacritic, e.g. cường.
300:             'O', 'o' => {}, // circumflex.
301:             'P', 'p' => {}, // fill missing diacritic, e.g. cướp.
302:             'R', 'r' => {}, // dipping_rising.
303:             'S', 's' => {}, // rising.
304:             'T', 't' => {}, // fill missing diacritic, e.g. trượt.
305:             'U', 'u' => {}, // fill missing diacritic, e.g. hươu.
306:             'W', 'w' => {}, // breve.
307:             'X', 'x' => {}, // rising_glottalized.
308:             'Z', 'z' => {}, // level / reset.
309:             else => { // literal.
310:                 // These characters will be added to state literally.
311:                 self.append_literal(c);
312:                 // Set modification index to null because we didn't modify any existing span.
313:                 self.buffer_modification_index = null;
314:                 // Set literal index if it's not set and the length exceed the buffer_effective.
315:                 if (self.literal_index == null and self.buffer_length > self.buffer_effective.len) {
316:                     // Set literal mode since buffer index 16 (just after the last buffer_effective
317:                     // item) because we don't have span for these position, we stop processing Telex
318:                     // rules but we will continue processing if user use backspaces to move back to the
319:                     // buffer_effective range, all existing spans must work as expected.
320:                     self.literal_index = self.buffer_effective.len;
321:                 }
322:             },
323:         }
324: 
325:         // Ensure the literal_index in valid state.
326:         if (self.mode == .literal) {
327:             assert(self.literal_index == null);
328:         }
329:     }
330: 
331:     // Append literal character when possible. Then inclease the buffer_length.
332:     fn append_literal(self: *State, c: u8) void {
333:         // Only allow a-zA-Z.
334:         assert(std.ascii.isAlphabetic(c));
335: 
336:         // Check if we can add new span for input character.
337:         if (self.buffer_length < self.buffer_effective.len) {
338:             // Add character to span.
339:             self.buffer_effective[self.buffer_length] = Span.init(c);
340:         }
341:         // Increase the buffer length for tracking, we will need it went handling backspace.
342:         self.buffer_length = self.buffer_length + 1;
343:     }
344: 
345:     fn backspace(self: *State) void {
346:         // buffer_length must be positive for backspace.
347:         assert(self.buffer_length > 0);
348: 
349:         // Input mode must be either .literal or .telex.
350:         assert(self.mode == .literal or self.mode == .telex);
351: 
352:         if (self.literal_index) |literal_index| {
353:             // Input mode must be .telex when literal_index is set.
354:             assert(self.mode == .telex);
355:             // literal_index must be within buffer range when set.
356:             assert(literal_index < self.buffer_length);
357:         }
358: 
359:         // decrease the buffer_length to match the backspace.
360:         self.buffer_length -= 1;
361:         // b cause backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
362:         self.buffer_modification_index = null;
363:         // if the literal_index is out of buffer range, unset it.
364:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
365:             self.literal_index = null;
366:         }
367:     }
368: };
